import api from './client';
import type { FormMode } from '@/components/forms/HarmonyForm';

export const formMetadataService = {
  // suppressErrorToast: HarmonyForm renders its own "Configuration Error" state on fetch failure.
  getFormMetadata: (dtoName: string, mode: FormMode = 'create') =>
    api.get(`/forms/${dtoName}`, { params: { mode }, suppressErrorToast: true }).then(r => r.data),
};
